function extractTextFromDocument(document) {
  var text = "";
  for (var I = 0; I < document.childNodes.length; i++) {
    var node = document.childNodes[i];
    if (node.nodeType === Node.TEXT_NODE) {
      text += node.textContent;
    }
  }
  return text;
}
```

