const fs = require('fs');

class PullStream {
  constructor(readableStream, writableStream) {
    this.readableStream = readableStream;
    this.writableStream = writableStream;
  }

  start() {
    this.readableStream.on('readable', () => {
      const chunk = this.readableStream.read();
      if (chunk) {
        this.writableStream.write(chunk);
