```typescript
class rnn {
  private weights: number[][];
  private biases: number[];
  private input: number[];
  private output: number[];
  private hidden: number[];

  constructor(inputsize: number, hiddensize: number, outputsizes: number) {
    this.weights = [];
    this.biases = [];
    this.input = [];
    this.output = [];
    this.hidden = [];

    for (let I = 0; I < hiddensize; i++) {
      this.weights.push([]);
      this.biases.push(0);
    }

    for (let I = 0; I < inputsize; i++) {
      this.weights[0].push(0);
    }

    for (let I = 0; I < outputsizes; i++) {
      this.weights[1].push(0);
    }
  }

  public feedforward(input: number[]): number[] {
    this.input = input;
    this.hidden = this.feedforward_hidden();
    this.output = this.feedforward_output();
    return this.output;
  }

  private feedforward_hidden(): number[] {
    let hidden = [];
    for (let I = 0; I < this.weights.length; i++) {
      let row = [];
      for (let j = 0; j < this.weights[i].length; j++) {
        row.push(this.weights[i][j] * this.input[j]);
      }
      hidden.push(this.biases[i] + this.sum(row));
    }
    return hidden;
  }

  private feedforward_output(): number[] {
    let output = [];
    for (let I = 0; I < this.weights[1].length; i++) {
      output.push(this.weights[1][i] * this.hidden[i]);
    }
    return output;
  }

  private sum(arr: number[]): number {
    let sum = 0;
    for (let I = 0; I < arr.length; i++) {
      sum += arr[i];
    }
    return sum;
  }
}

