```javascript
function searchEntityValue(json, entityKey) {
  // Base case: if the json is not an object, return null
  if (!isObject(json)) {
    return null;
  }

  // Recursive case: if the json is an object, search for the entity key
  if (isObject(json)) {
    for (let key in json) {
      if (key === entityKey) {
        // If the entity key is found, return the value and the entity key location
        return { value: json[key], location: key };
      } else if (isObject(json[key])) {
        // If the value of the current key is an object, recurse the function with the object as the new json parameter
        const result = searchEntityValue(json[key], entityKey);
        if (result) {
          // If the entity key is found in the object, return the value and the entity key location
          return { value: result.value, location: `${result.location}.${key}` };
        }
      }
    }
  }

  // If the entity key is not found, return null
  return null;
}
```

This function takes two parameters: the JSON object to search and the entity key to search for. It returns an object with two properties: the value of the entity key and the location of the entity key in the JSON object (as a string). If the entity key is not found, the function returns null.

